o=[A.W(["id",1,"nama","Puntadewa (Prabu Yudistira)","afiliasi","Pandawa","deskripsi","Putra sulung Pandawa, titisan Batara Darma. Dalam pewayangan Jawa ia dikenal sebagai Prabu Puntadewa, raja Amarta yang adil dan jujur. Tidak pernah berdusta dan selalu mengutamakan dharma dalam setiap langkahnya.","image_asset","assets/wayang/puntadewa.webp","rarity","Langka","kekuatan","Kebijaksanaan tertinggi, wahana kereta Jemparing Baruna yang tidak menyentuh tanah selama ia berlaku jujur.","pusaka","Tombak Kaladanda (anugerah Batara Darma)","nilai_moral","Kejujuran, Keadilan, dan Keteguhan Hati"],q,p),A.W(["id",2,"nama","Werkudara (Bratasena / Bima)","afiliasi","Pandawa","deskripsi","Putra kedua Pandawa, titisan Batara Bayu. Dalam pewayangan Jawa, Bima lebih sering disebut Werkudara atau Bratasena. Ia selalu berbicara lurus tanpa basa-basi bahkan kepada dewa sekalipun, lambang ksatria yang tidak mengenal kemunafikan.","image_asset","assets/wayang/werkudara.webp","rarity","Langka","kekuatan","Kekuatan fisik tak tertandingi, Aji Bandung Bandawasa, dan Aji Blabak Pangantol-antol.","pusaka","Gada Rujakpala & Kuku Pancanaka","nilai_moral","Keberanian, Kesetiaan, dan Integritas tanpa Kompromi"],q,p),A.W(["id",3,"nama","Janaka (Permadi / Dananjaya / Arjuna)","afiliasi","Pandawa","deskripsi","Putra ketiga Pandawa, titisan Batara Indra. Dalam pewayangan Jawa ia memiliki banyak nama gelar: Janaka, Permadi, Dananjaya, Palguna. Ksatria paling tampan dan pemanah paling sakti di Tanah Jawa.","image_asset","assets/wayang/janaka.webp","rarity","Legendaris","kekuatan","Keahlian memanah tanpa tanding, ilmu Bramastra, dan Aji Panglimunan (menghilang).","pusaka","Panah Pasopati (anugerah Batara Guru) & Busur Gandiwa","nilai_moral","Dedikasi, Disiplin, dan Kerendahan Hati di Hadapan Ilmu"],q,p),A.W(["id",4,"nama","Nakula","afiliasi","Pandawa","deskripsi","Putra keempat Pandawa, anak dari Batara Aswin (kembar dengan Sadewa). Nakula sangat tampan dan dikenal ahli dalam merawat kuda dan ilmu pengobatan. Ia adalah sosok yang setia pada keluarga.","image_asset","assets/wayang/nakula.webp","rarity","Umum","kekuatan","Ahli ilmu pedang dan perawatan kuda. Memiliki pengetahuan luas tentang obat-obatan.","pusaka","Pedang Nagasasra","nilai_moral","Kesetiaan Keluarga dan Ketelitian"],q,p),A.W(["id",5,"nama","Sadewa","afiliasi","Pandawa","deskripsi","Putra kelima Pandawa, saudara kembar Nakula dari Batara Aswin. Sadewa adalah yang paling cerdas di antara Pandawa dalam hal ilmu perbintangan dan ramalan. Ia sangat patuh dan penuh hormat.","image_asset","assets/wayang/sadewa.webp","rarity","Umum","kekuatan","Ilmu astrologi dan ramalan yang sangat akurat. Dapat membaca tanda-tanda alam dan nasib seseorang.","pusaka","Keris Saraswati","nilai_moral","Kecerdasan, Kepatuhan, dan Rasa Hormat"],q,p),A.W(["id",6,"nama","Sri Kresna (Prabu Kresna)","afiliasi","Sekutu Pandawa","deskripsi","Raja Dwarawati, titisan Batara Wisnu. Dalam pewayangan Jawa, Kresna adalah tokoh terpenting di pihak Pandawa \u2014 penasihat, diplomat, dan penggerak strategi perang Bharatayuda. Ia juga menyampaikan Wulang (ajaran) kepada Janaka sebelum perang.","image_asset","assets/wayang/sri_kresna.webp","rarity","Legendaris","kekuatan","Kecerdasan taktis, ilmu sastra jendra (ilmu kehidupan), dan wujud Wiswarupa.","pusaka","Cakra Sudarsana & Terompet Panchajanya","nilai_moral","Kebijaksanaan Sejati, Dharma, dan Pengabdian Tanpa Pamrih"],q,p),A.W(["id",7,"nama","Gatotkaca","afiliasi","Sekutu Pandawa","deskripsi","Putra Bima dari Dewi Arimbi, keturunan raksasa yang gagah. Gatotkaca memiliki tubuh raksasa dan bisa terbang. Ia gugur di tangan Karna menggunakan senjata Kunta, namun kematiannya menyelamatkan Arjuna.","image_asset","assets/wayang/gatotkaca.webp","rarity","Langka","kekuatan","Tubuh kebal senjata, mampu terbang, dan kekuatan raksasa yang berlipat ganda di malam hari.","pusaka","Anting-anting Keramat (Carub Niskala)","nilai_moral","Pengorbanan Jiwa untuk Melindungi yang Dicintai"],q,p),A.W(["id",8,"nama","Abimanyu","afiliasi","Sekutu Pandawa","deskripsi","Putra Arjuna dari Subadra. Abimanyu sudah belajar ilmu perang sejak dalam kandungan. Ia gugur secara heroik dalam formasi Cakravyuha pada perang Bharatayudha, dikeroyok banyak ksatria Kurawa.","image_asset","assets/wayang/abimanyu.webp","rarity","Langka","kekuatan","Kemability menembus formasi Cakravyuha yang tidak bisa dilakukan ksatria lain. Keberanian yang melampaui usianya.","pusaka","Busur Warisan Arjuna","nilai_moral","Kepahlawanan Sejati dan Pantang Menyerah Meski Sendirian"],q,p),A.W(["id",9,"nama","Suyudhana (Prabu Duryudana)","afiliasi","Kurawa","deskripsi","Putra sulung Drestarastra, Raja Ngastina yang menjadi pemimpin Kurawa. Dalam pewayangan Jawa namanya yang benar adalah Suyudhana (bukan Duryodhana). Ia menolak membagi kerajaan dengan Pandawa dan menjadi tokoh utama pemicu perang Bharatayuda.","image_asset","assets/wayang/suyudhana.webp","rarity","Langka","kekuatan","Ilmu gada Kalimasada dan tubuh kebal senjata berkat pandangan Dewi Gendari, kecuali bagian paha.","pusaka","Gada Kyai Kalimasada","nilai_moral","(Pelajaran negatif) Bahaya Iri Hati dan Kesombongan yang Menghancurkan Diri Sendiri"],q,p),A.W(["id",10,"nama","Adipati Karna","afiliasi","Kurawa","deskripsi","Dalam pewayangan Jawa disebut Adipati Karna atau Basukarna. Ia adalah putra pertama Dewi Kunti yang dirahasiakan. Dibesarkan oleh kusir kereta di Kerajaan Awangga. Memihak Kurawa karena kesetiaan murni pada Suyudhana yang memberinya kehormatan.","image_asset","assets/wayang/adipati_karna.webp","rarity","Legendaris","kekuatan","Pemanah setara Janaka, memiliki anugerah Kavacha-Kundala (baju zirah & anting sakti) sejak lahir.","pusaka","Panah Kunta & Kavacha-Kundala","nilai_moral","Kesetiaan pada Sahabat dan Tragedi Takdir yang Tidak Adil"],q,p),A.W(["id",11,"nama","Sakuni","afiliasi","Kurawa","deskripsi","Paman Duryudhana dari kerajaan Gandhara. Sakuni adalah otak di balik berbagai tipu muslihat yang menimpa Pandawa, termasuk permainan dadu yang menyebabkan Pandawa diasingkan 12 tahun.","image_asset","assets/wayang/sakuni.webp","rarity","Umum","kekuatan","Kecerdasan licik dan kemampuan memanipulasi situasi. Ahli dalam permainan dadu menggunakan dadu bertuah yang terbuat dari tulang ayahnya.","pusaka","Dadu Tulang Keramat","nilai_moral","(Pelajaran negatif) Kecerdasan yang Dipakai untuk Kejahatan Hanya Membawa Kehancuran"],q,p),A.W(["id",12,"nama","Resi Bisma (Dewabrata)","afiliasi","Pihak Ngastina (Netral)","deskripsi","Putra Prabu Sentanu dan Dewi Gangga, nama aslinya Dewabrata. Dalam pewayangan Jawa, Resi Bisma adalah tokoh paling dihormati \u2014 sesepuh kerajaan Ngastina yang bersumpah tidak akan menikah. Anugerahnya: menentukan waktu kematiannya sendiri.","image_asset","assets/wayang/resi_bisma.webp","rarity","Legendaris","kekuatan","Ilmu perang tertinggi, Aji Swiwikrama (membesarkan diri), anugerah Iccha Mrityu.","pusaka","Busur Brahmanda","nilai_moral","Pengorbanan Pribadi demi Sumpah yang Lebih Besar dari Diri Sendiri"],q,p),A.W(["id",13,"nama","Resi Drona (Sokalima)","afiliasi","Pihak Ngastina","deskripsi","Guru besar ilmu perang bagi semua pangeran Kuru. Dalam pewayangan Jawa, Drona tinggal di pertapaan Sokalima. Ia mengajarkan ilmu Bramastra kepada Janaka namun juga memihak Kurawa saat perang Bharatayuda.","image_asset","assets/wayang/resi_drona.webp","rarity","Langka","kekuatan","Penguasaan semua ilmu senjata dan Bramastra yang mematikan.","pusaka","Senjata Bramastra","nilai_moral","Dedikasi pada Ilmu, namun juga Peringatan tentang Keberpihakan yang Tidak Adil"],q,p),A.W(["id",14,"nama","Dewi Wara Drupadi","afiliasi","Sekutu Pandawa","deskripsi","Putri Raja Drupada yang lahir dari api suci, menjadi istri kelima Pandawa (Dalam versi Jawa hanya istri Yudistira). Penghinaan yang diterimanya di muka umum oleh Dursasana menjadi pemicu utama perang Bharatayuda.","image_asset","assets/wayang/dewi_drupadi.webp","rarity","Langka","kekuatan","Keteguhan batin dan dilindungi secara gaib oleh Sri Kresna \u2014 kain yang ditariknya tidak akan pernah habis.","pusaka","Perlindungan Suci Sri Kresna","nilai_moral","Martabat Diri, Keberanian Wanita, dan Keadilan yang Harus Diperjuangkan"],q,p),A.W(["id",15,"nama","Dewi Srikandi","afiliasi","Sekutu Pandawa","deskripsi","Putri Raja Drupada, saudara Dewi Drupadi. Dalam pewayangan Jawa, Srikandi adalah murid Janaka (Arjuna) dalam ilmu memanah dan kemudian menjadi istrinya. Ia menjadi kunci penghancur Resi Bisma dalam perang Bharatayuda.","image_asset","assets/wayang/dewi_srikandi.webp","rarity","Langka","kekuatan","Keahlian memanah setara ksatria, murid terbaik Janaka.","pusaka","Panah Ardhadedali","nilai_moral","Keberanian Menembus Batas dan Tidak Menyerah pada Ketidakadilan"],q,p),A.W(["id",16,"nama","Batara Guru (Dewa Siwa)","afiliasi","Dewa","deskripsi","Penguasa tertinggi Kahyangan dalam kosmologi pewayangan Jawa. Batara Guru adalah wujud Siwa yang paling dihormati. Ia pemberi anugerah kepada ksatria pilihan, termasuk memberikan senjata Pasopati kepada Janaka.","image_asset","assets/wayang/batara_guru.webp","rarity","Legendaris","kekuatan","Penguasaan semesta, sumber segala senjata sakti dan anugerah.","pusaka","Trisula Suci","nilai_moral","Kebijaksanaan Agung dan Keseimbangan Alam"],q,p),A.W(["id",17,"nama","Batara Indra","afiliasi","Dewa","deskripsi","Raja para dewa di Kahyangan, ayah kandung Janaka (Arjuna). Dalam pewayangan Jawa, Batara Indra sering turun membantu para ksatria pilihan dan mengajari Janaka ilmu perang di Kahyangan.","image_asset","assets/wayang/batara_indra.webp","rarity","Langka","kekuatan","Penguasa petir dan hujan, memiliki pasukan Kahyangan.","pusaka","Bajra (Senjata Halilintar)","nilai_moral","Keberanian dan Perlindungan kepada yang Lemah"],q,p),A.W(["id",18,"nama","Semar (Batara Ismaya)","afiliasi","Punakawan","deskripsi","Sosok paling agung dalam pewayangan Jawa. Semar sejatinya adalah Batara Ismaya, dewa yang rela turun ke bumi menjadi abdi para ksatria Pandawa. Wujudnya jelek namun kebijaksanaannya melampaui para dewa.","image_asset","assets/wayang/semar.webp","rarity","Legendaris","kekuatan","Kebijaksanaan tak terbatas, kekuatan gaib tersembunyi.","pusaka","Kentut Semar (senjata pamungkas yang tak tertandingi)","nilai_moral","Kerendahan Hati Sejati \u2014 yang Mulia tidak perlu terlihat mulia"],q,p),A.W(["id",19,"nama","Nala Gareng","afiliasi","Punakawan","deskripsi","Putra angkat pertama Semar. Gareng cacat fisik yang melambangkan manusia penuh kekurangan namun tetap bersemangat. Dalam banyak lakon ia menjadi penghibur sekaligus penyampai pesan moral.","image_asset","assets/wayang/gareng.webp","rarity","Umum","kekuatan","Ketangkasan dan kecerdikan meski penuh keterbatasan fisik.","pusaka","Cengkeraman Tangan Ciker","nilai_moral","Jangan Merasa Rendah Diri karena Kekurangan Fisik"],q,p),A.W(["id",20,"nama","Petruk (Kanthong Bolong)","afiliasi","Punakawan","deskripsi",'Putra angkat kedua Semar, dikenal dengan hidung panjang dan tubuh jangkung. Petruk adalah Punakawan paling humoris dan cerdas. Dalam lakon "Petruk dadi Ratu," ia bahkan berhasil merebut kerajaan sementara.',"image_asset","assets/wayang/petruk.webp","rarity","Umum","kekuatan","Kecerdikan, kelincahan, dan kemampuan bersilat lidah.","pusaka","Gada Kanthong Bolong","nilai_moral","Kecerdasan Rakyat Jelata Bisa Mengalahkan Kesombongan Bangsawan"],q,p)]
