o=[A.W(["level",1,"kategori","Pengenalan Wayang","pertanyaan",'Wayang berasal dari kata "Ma Hyang" yang berarti...',"pilihan_a","Bergerak mengikuti angin","pilihan_b","Menuju kepada yang Maha Tinggi (Tuhan)","pilihan_c","Bayangan manusia purba","pilihan_d","Pertunjukan raja-raja Jawa","jawaban_benar","B","penjelasan",'Kata "Wayang" berasal dari bahasa Jawa Kuno "Ma Hyang" yang artinya menuju kepada roh leluhur atau yang Maha Tinggi.'],q,p),A.W(["level",1,"kategori","Pengenalan Wayang","pertanyaan","Wayang diakui sebagai Warisan Budaya Takbenda oleh UNESCO pada tahun...","pilihan_a","2003","pilihan_b","2001","pilihan_c","1998","pilihan_d","2005","jawaban_benar","A","penjelasan","UNESCO mengakui Wayang Indonesia sebagai Masterpiece of the Oral and Intangible Heritage of Humanity pada tanggal 7 November 2003."],q,p),A.W(["level",1,"kategori","Pengenalan Wayang","pertanyaan","Layar putih yang digunakan sebagai media pertunjukan wayang kulit disebut...","pilihan_a","Blencong","pilihan_b","Gedebog","pilihan_c","Gunungan","pilihan_d","Kelir","jawaban_benar","D","penjelasan","Kelir adalah layar putih yang menjadi tempat bayangan wayang diproyeksikan selama pertunjukan berlangsung."],q,p),A.W(["level",1,"kategori","Pengenalan Wayang","pertanyaan","Lampu yang digunakan untuk menerangi pertunjukan wayang kulit tradisional disebut...","pilihan_a","Blencong","pilihan_b","Senthir","pilihan_c","Kelir","pilihan_d","Debog","jawaban_benar","A","penjelasan","Blencong adalah lampu minyak tradisional yang digunakan untuk menerangi kelir dan menciptakan efek bayangan wayang."],q,p),A.W(["level",1,"kategori","Pengenalan Wayang","pertanyaan","Wayang yang terbuat dari kulit kerbau dan dimainkan dengan bayangan adalah...","pilihan_a","Wayang Golek","pilihan_b","Wayang Kulit","pilihan_c","Wayang Orang","pilihan_d","Wayang Klitik","jawaban_benar","B","penjelasan","Wayang Kulit adalah jenis wayang yang paling terkenal, terbuat dari kulit kerbau yang dipahat halus dan dimainkan di balik layar dengan bayangan."],q,p),A.W(["level",1,"kategori","Pengenalan Wayang","pertanyaan","Wayang yang berbentuk tiga dimensi (3D) dan terbuat dari kayu adalah...","pilihan_a","Wayang Kulit","pilihan_b","Wayang Beber","pilihan_c","Wayang Golek","pilihan_d","Wayang Klitik","jawaban_benar","C","penjelasan","Wayang Golek adalah boneka kayu tiga dimensi yang biasanya digunakan di pertunjukan Sunda (Jawa Barat), tanpa menggunakan layar bayangan."],q,p),A.W(["level",1,"kategori","Pengenalan Wayang","pertanyaan","Pemimpin pertunjukan wayang yang mengendalikan semua boneka dan bercerita disebut...","pilihan_a","Sinden","pilihan_b","Niyaga","pilihan_c","Wiraswara","pilihan_d","Dalang","jawaban_benar","D","penjelasan","Dalang adalah seniman utama pertunjukan wayang yang mengendalikan semua boneka, membacakan dialog, dan menceritakan lakon (kisah)."],q,p),A.W(["level",1,"kategori","Pengenalan Wayang","pertanyaan","Tokoh wayang yang digambarkan berbentuk gunung/kipas dan merupakan simbol keseimbangan dunia disebut...","pilihan_a","Kresna","pilihan_b","Gunungan (Kayon)","pilihan_c","Semar","pilihan_d","Togog","jawaban_benar","B","penjelasan","Gunungan atau Kayon adalah wayang berbentuk gunung yang digunakan sebagai pembuka/penutup pertunjukan dan melambangkan keseimbangan alam semesta."],q,p),A.W(["level",1,"kategori","Pengenalan Wayang","pertanyaan","Boneka wayang ditancapkan pada batang pohon pisang yang disebut...","pilihan_a","Kelir","pilihan_b","Blencong","pilihan_c","Gedebog","pilihan_d","Kothak","jawaban_benar","C","penjelasan","Gedebog adalah batang pohon pisang yang digunakan sebagai tempat menancapkan gagang wayang selama pertunjukan berlangsung."],q,p),A.W(["level",1,"kategori","Pengenalan Wayang","pertanyaan","Lakon (kisah) terbesar yang sering dimainkan dalam pertunjukan wayang adalah...","pilihan_a","Ramayana dan Mahabharata","pilihan_b","Serat Centhini dan Babad Tanah Jawi","pilihan_c","Panji dan Menak","pilihan_d","Sri dan Sadana","jawaban_benar","A","penjelasan","Ramayana dan Mahabharata adalah dua epos terbesar asal India yang paling sering diadaptasi dalam pertunjukan wayang kulit Jawa."],q,p),A.W(["level",2,"kategori","Silsilah Pandawa & Kurawa","pertanyaan","Siapakah tokoh yang mendirikan kota Hastinapura sebagai pusat pemerintahan?","pilihan_a","Sang Hasti","pilihan_b","Sang Kuru","pilihan_c","Sang Bharata","pilihan_d","Pratipa","jawaban_benar","A","penjelasan","Sang Hasti adalah keturunan Sang Bharata yang mendirikan kota Hastinapura."],q,p),A.W(["level",2,"kategori","Silsilah Pandawa & Kurawa","pertanyaan",'Dewabrata berganti nama menjadi Bisma karena melakukan sumpah yang disebut "Bhishan Pratigya." Isi sumpah tersebut adalah...',"pilihan_a","Tidak akan pernah berperang melawan Pandawa","pilihan_b","Membujang selamanya dan tidak mewarisi takhta ayahnya","pilihan_c","Selalu melindungi kerajaan Hastinapura sampai mati","pilihan_d","Tidak akan pernah menyerang dari belakang","jawaban_benar","B","penjelasan","Dewabrata bersumpah membujang seumur hidup dan tidak mewarisi takhta."],q,p),A.W(["level",2,"kategori","Silsilah Pandawa & Kurawa","pertanyaan","Mengapa Drestarastra terlahir dalam keadaan buta?","pilihan_a","Dikutuk oleh Resi Byasa sebelum lahir","pilihan_b","Ayahnya memiliki penyakit bawaan","pilihan_c","Ibunya (Ambika) menutup mata selama upacara dengan Resi Byasa berlangsung","pilihan_d","Lahir prematur","jawaban_benar","C","penjelasan","Ambika terkejut dengan wajah sakti Resi Byasa lalu menutup mata, sehingga anaknya (Drestarastra) lahir buta."],q,p),A.W(["level",2,"kategori","Silsilah Pandawa & Kurawa","pertanyaan","Mengapa Pandu terlahir berwarna pucat?","pilihan_a","Lahir prematur","pilihan_b","Kutukan dewa","pilihan_c","Keturunan penyakit","pilihan_d","Ibunya (Ambalika) menjadi sangat pucat ketakutan saat melihat Resi Byasa","jawaban_benar","D","penjelasan","Ambalika membuka mata namun sangat ketakutan dan pucat, sehingga Pandu terlahir pucat."],q,p),A.W(["level",2,"kategori","Silsilah Pandawa & Kurawa","pertanyaan","Widura adalah putra Resi Byasa dari siapa, dan mengapa ia lahir dengan kaki pincang?","pilihan_a","Dari dayang Datri, lahir pincang karena Datri berlari keluar saat upacara","pilihan_b","Dari Ambika, kena kutukan","pilihan_c","Dari Ambalika","pilihan_d","Dari Satyawati","jawaban_benar","A","penjelasan","Datri ketakutan dan berlari keluar kamar hingga terjatuh, sehingga Widura lahir pincang."],q,p),A.W(["level",2,"kategori","Silsilah Pandawa & Kurawa","pertanyaan","Pandu mendapat kutukan tidak bisa punya anak karena memanah seekor kijang yang ternyata adalah...","pilihan_a","Dewa pelindung hutan","pilihan_b","Utusan Batara Guru","pilihan_c","Seorang pendeta sakti yang sedang kasmaran","pilihan_d","Raja iblis","jawaban_benar","C","penjelasan","Kijang tersebut adalah pendeta yang menjelma. Sang pendeta mengutuk Pandu sebelum mati."],q,p),A.W(["level",2,"kategori","Silsilah Pandawa & Kurawa","pertanyaan","Siapa yang memberikan mantra kepada Dewi Kunti agar bisa memanggil dewa?","pilihan_a","Resi Byasa","pilihan_b","Resi Druwasa","pilihan_c","Batara Guru","pilihan_d","Prabu Santanu","jawaban_benar","B","penjelasan","Resi Druwasa memberikan mantra sakti kepada Kunti karena pelayanannya yang baik."],q,p),A.W(["level",2,"kategori","Silsilah Pandawa & Kurawa","pertanyaan","Karna adalah anak pertama Dewi Kunti dari Batara Surya. Apa yang terjadi kepadanya?","pilihan_a","Dibesarkan Kunti diam-diam","pilihan_b","Dikirim ke pertapaan","pilihan_c","Tinggal bersama Pandawa","pilihan_d","Dilarung ke sungai dan dirawat oleh kusir di Awangga","jawaban_benar","D","penjelasan","Kunti membuang Karna ke sungai, lalu ia dirawat oleh Adirata si kusir."],q,p),A.W(["level",2,"kategori","Silsilah Pandawa & Kurawa","pertanyaan","Pasangan dewa mana yang membuahi Dewi Madrim sehingga lahir Nakula dan Sadewa?","pilihan_a","Batara Aswan dan Batara Aswin","pilihan_b","Bayu dan Indra","pilihan_c","Surya dan Darma","pilihan_d","Wisnu dan Siwa","jawaban_benar","A","penjelasan","Dewa kembar Aswan dan Aswin memberikan anugerah anak kembar, Nakula dan Sadewa."],q,p),A.W(["level",2,"kategori","Silsilah Pandawa & Kurawa","pertanyaan","Drestarastra menikah dengan Dewi Gendari dan memiliki berapa anak?","pilihan_a","50 putra, 2 putri","pilihan_b","100 putra, 0 putri","pilihan_c","99 putra, 1 putri","pilihan_d","99 putra, 2 putri","jawaban_benar","C","penjelasan","Mereka memiliki 99 orang putra dan 1 putri yang dikenal sebagai Kurawa."],q,p),A.W(["level",3,"kategori","Konflik & Pengasingan","pertanyaan","Lakon apa yang menceritakan rencana Kurawa membakar rumah Pandawa?","pilihan_a","Baratayuda","pilihan_b","Bale Sigala-gala","pilihan_c","Pandawa Seda","pilihan_d","Dewa Ruci","jawaban_benar","B","penjelasan","Peristiwa pembakaran rumah Pandawa (Bale Sigala-gala). Pandawa selamat karena bantuan Widura."],q,p),A.W(["level",3,"kategori","Konflik & Pengasingan","pertanyaan","Siapa yang memberitahu Pandawa tentang rencana pembakaran tersebut?","pilihan_a","Sri Kresna","pilihan_b","Resi Bisma","pilihan_c","Widura","pilihan_d","Sengkuni","jawaban_benar","C","penjelasan","Widura yang merupakan paman Pandawa memberitahu mereka tentang rencana jahat tersebut."],q,p),A.W(["level",3,"kategori","Konflik & Pengasingan","pertanyaan","Dalam pedalangan Jawa, ayah raksasa Arimba bernama...","pilihan_a","Trembaka (Arimbaka)","pilihan_b","Hidimba","pilihan_c","Pracona","pilihan_d","Yaksadewa","jawaban_benar","A","penjelasan","Dalam versi Jawa, ayahnya adalah Trembaka. Adik Arimba yaitu Arimbi kemudian menikahi Bima."],q,p),A.W(["level",3,"kategori","Konflik & Pengasingan","pertanyaan","Dalam versi pedalangan Jawa, Dewi Drupadi adalah istri dari...","pilihan_a","Kelima Pandawa","pilihan_b","Janaka (Arjuna)","pilihan_c","Werkudara (Bima)","pilihan_d","Puntadewa (Yudistira) seorang","jawaban_benar","D","penjelasan","Berbeda dengan versi India di mana ia bersuami lima, dalam wayang Jawa ia hanya istri Yudistira."],q,p),A.W(["level",3,"kategori","Konflik & Pengasingan","pertanyaan","Ibukota kerajaan Pandawa adalah...","pilihan_a","Indraprastha","pilihan_b","Hastinapura","pilihan_c","Pancala","pilihan_d","Dwarawati","jawaban_benar","A","penjelasan","Pandawa membangun Indraprastha di tanah Kurujanggala yang tadinya merupakan hutan gersang."],q,p),A.W(["level",3,"kategori","Konflik & Pengasingan","pertanyaan","Apa yang membuat Duryudana sangat membenci Pandawa saat mengunjungi Indraprastha?","pilihan_a","Melihat kekayaan mereka","pilihan_b","Dihina Kresna","pilihan_c","Ia tercebur kolam yang dikira lantai, lalu ditertawakan Drupadi","pilihan_d","Tidak diberi jamuan","jawaban_benar","C","penjelasan","Duryudana tertipu oleh lantai kristal dan tercebur ke air, menjadi bahan ejekan."],q,p),A.W(["level",3,"kategori","Konflik & Pengasingan","pertanyaan",'Siapa "bandar dadu" Kurawa yang curang menjebak Pandawa?',"pilihan_a","Dursasana","pilihan_b","Karna","pilihan_c","Drona","pilihan_d","Arya Sengkuni","jawaban_benar","D","penjelasan","Arya Sengkuni adalah otak kelicikan yang menggunakan dadu bertuah untuk mengalahkan Yudistira."],q,p),A.W(["level",3,"kategori","Konflik & Pengasingan","pertanyaan","Mengapa Sri Kresna membantu agar kain Drupadi tidak habis saat ditarik?","pilihan_a","Kresna kakaknya","pilihan_b","Drupadi pernah membalut luka jari Kresna","pilihan_c","Anugerah dewa","pilihan_d","Sihir dari cincin","jawaban_benar","B","penjelasan","Drupadi membalut jari Kresna yang terluka saat upacara Rajasuya, dibalas dengan perlindungan kain tak terbatas."],q,p),A.W(["level",3,"kategori","Konflik & Pengasingan","pertanyaan","Sumpah Drupadi setelah dipermalukan Dursasana adalah...","pilihan_a","Tidak menggelung rambut sebelum dikeramas dengan darah Dursasana","pilihan_b","Membunuh Duryudana","pilihan_c","Meninggalkan Pandawa","pilihan_d","Mengutuk Hastina","jawaban_benar","A","penjelasan","Drupadi bersumpah tidak akan merapikan rambutnya hingga dibasuh darah Dursasana."],q,p),A.W(["level",3,"kategori","Konflik & Pengasingan","pertanyaan","Berapa lama total hukuman pengasingan Pandawa setelah kalah dadu?","pilihan_a","10 tahun + 2 tahun menyamar","pilihan_b","Ibunya menyamar","pilihan_c","12 tahun di hutan + 1 tahun menyamar","pilihan_d","14 tahun penuh","jawaban_benar","C","penjelasan","Mereka dihukum buang selama 12 tahun di hutan dan 1 tahun masa penyamaran (incognito)."],q,p),A.W(["level",4,"kategori","Perang Bharatayuda","pertanyaan","Berapa hari perang Bharatayuda berlangsung?","pilihan_a","10 hari","pilihan_b","14 hari","pilihan_c","18 hari","pilihan_d","21 hari","jawaban_benar","C","penjelasan","Perang suci ini berlangsung selama 18 hari penuh di Kurusetra."],q,p),A.W(["level",4,"kategori","Perang Bharatayuda","pertanyaan","Siapa panglima Kurawa pada hari 1-10?","pilihan_a","Resi Bisma","pilihan_b","Resi Drona","pilihan_c","Adipati Karna","pilihan_d","Salya","jawaban_benar","A","penjelasan","Resi Bisma menjadi senapati pertama dan tak terkalahkan hingga hari ke-10."],q,p),A.W(["level",4,"kategori","Perang Bharatayuda","pertanyaan","Mengapa Arjuna menggunakan Srikandi sebagai tameng melawan Bisma?","pilihan_a","Srikandi kebal senjata","pilihan_b","Bisma bersumpah tidak akan menyerang perempuan","pilihan_c","Srikandi adik Arjuna","pilihan_d","Perintah dewa","jawaban_benar","B","penjelasan","Bisma tidak menyerang Srikandi karena sumpah ksatria-nya, sehingga Arjuna bisa menyerang dari balik Srikandi."],q,p),A.W(["level",4,"kategori","Perang Bharatayuda","pertanyaan","Formasi melingkar yang menjebak Abimanyu disebut...","pilihan_a","Garuda Byuha","pilihan_b","Makara Byuha","pilihan_c","Padma","pilihan_d","Cakravyuha","jawaban_benar","D","penjelasan","Cakravyuha adalah formasi buatan Drona. Abimanyu tahu cara masuk namun tak tahu cara keluar."],q,p),A.W(["level",4,"kategori","Perang Bharatayuda","pertanyaan","Bagaimana cara Pandawa mengalahkan Resi Drona?","pilihan_a","Bramastra","pilihan_b","Bantuan Semar","pilihan_c","Dekeroyok Bima dan Arjuna","pilihan_d","Menyebarkan kabar bohong bahwa putranya (Aswatama) mati","jawaban_benar","D","penjelasan","Kabar bohong gugurnya Aswatama membuat Drona kehilangan semangat bertarung dan menundukkan senjata."],q,p),A.W(["level",4,"kategori","Perang Bharatayuda","pertanyaan","Siapa panglima Kurawa pada hari ke-16?","pilihan_a","Aswatama","pilihan_b","Adipati Karna","pilihan_c","Sengkuni","pilihan_d","Salya","jawaban_benar","B","penjelasan","Adipati Karna menggantikan Drona sebagai panglima tertinggi."],q,p),A.W(["level",4,"kategori","Perang Bharatayuda","pertanyaan","Mengapa Karna kesulitan melawan Arjuna di akhir?","pilihan_a","Roda keretanya terperosok ke lumpur","pilihan_b","Kehabisan panah","pilihan_c","Zirahnya hilang","pilihan_d","Terkena sihir Kresna","jawaban_benar","A","penjelasan","Karena kutukan, roda kereta Karna amblas ke tanah dan ia lupa mantra senjatanya."],q,p),A.W(["level",4,"kategori","Perang Bharatayuda","pertanyaan","Siapa yang gugur di dalam formasi Cakravyuha?","pilihan_a","Gatotkaca","pilihan_b","Irawan","pilihan_c","Abimanyu","pilihan_d","Utara","jawaban_benar","C","penjelasan","Abimanyu gugur setelah dikeroyok oleh ksatria utama Kurawa dalam Cakravyuha."],q,p),A.W(["level",4,"kategori","Perang Bharatayuda","pertanyaan","Bagaimana Bima mengalahkan Duryudana?","pilihan_a","Panah Pasopati","pilihan_b","Kuku Pancanaka","pilihan_c","Memukul pahanya dengan gada","pilihan_d","Mencekiknya","jawaban_benar","C","penjelasan","Paha Duryudana adalah satu-satunya bagian tubuhnya yang tidak kebal senjata."],q,p),A.W(["level",4,"kategori","Perang Bharatayuda","pertanyaan","Pasukan sekutu Pandawa yang gugur di awal perang adalah...","pilihan_a","Prabu Matswapati dan putra-putranya","pilihan_b","Prabu Drupada","pilihan_c","Punakawan","pilihan_d","Kresna","jawaban_benar","A","penjelasan","Raja Wirata (Matswapati) kehilangan putra-putranya seperti Utara, Seta, dan Wratsangka."],q,p),A.W(["level",5,"kategori","Filosofi & Nilai Moral","pertanyaan","Kisah Pandawa yang sabar menghadapi Kurawa mengajarkan bahwa...","pilihan_a","Orang lemah pasti kalah","pilihan_b","Kesabaran sejati adalah menunggu waktu yang tepat untuk menegakkan kebenaran","pilihan_c","Kekerasan adalah satu-satunya solusi","pilihan_d","Diam itu emas","jawaban_benar","B","penjelasan","Kesabaran Pandawa adalah kekuatan untuk bertahan hingga saatnya menegakkan Dharma."],q,p),A.W(["level",5,"kategori","Filosofi & Nilai Moral","pertanyaan","Karna memihak Kurawa meski tahu Pandawa benar. Ini mengajarkan tragedi...","pilihan_a","Kesetiaan pada kawan yang salah bisa berujung pada kebinasaan mulia","pilihan_b","Kekuatan adalah segalanya","pilihan_c","Jangan percaya keluarga","pilihan_d","Orang baik selalu menang","jawaban_benar","A","penjelasan","Karna setia pada Duryudana yang menolongnya saat dibuang, meski ia tahu berada di pihak yang salah."],q,p),A.W(["level",5,"kategori","Filosofi & Nilai Moral","pertanyaan","Kisah Sengkuni mengajarkan bahwa...","pilihan_a","Kecerdasan selalu membawa sukses","pilihan_b","Politik itu kotor","pilihan_c","Paman adalah pembimbing terbaik","pilihan_d","Kecerdasan yang digunakan untuk licik hanya membawa kehancuran","jawaban_benar","D","penjelasan","Semua kelicikan Sengkuni akhirnya menghancurkan keluarga Kurawa dan dirinya sendiri."],q,p),A.W(["level",5,"kategori","Filosofi & Nilai Moral","pertanyaan","Pelajaran dari tokoh Semar adalah...","pilihan_a","Kekuatan fisik itu penting","pilihan_b","Pengabdian untuk raja","pilihan_c","Kerendahan hati sejati, yang mulia tidak perlu terlihat mulia","pilihan_d","Lucu itu penting","jawaban_benar","C","penjelasan","Semar adalah dewa agung namun berwujud abdi yang jelek, melambangkan kerendahan hati mutlak."],q,p),A.W(["level",5,"kategori","Filosofi & Nilai Moral","pertanyaan","Sumpah Bisma mengajarkan...","pilihan_a","Pengorbanan pribadi demi janji yang lebih besar","pilihan_b","Jangan pernah berjanji","pilihan_c","Kesetiaan buta","pilihan_d","Kekuatan membujang","jawaban_benar","A","penjelasan","Bisma rela berkorban segalanya demi kebahagiaan ayahnya dan kesejahteraan Hastinapura."],q,p),A.W(["level",5,"kategori","Filosofi & Nilai Moral","pertanyaan","Setelah perang, Yudistira dinobatkan menjadi raja bergelar...","pilihan_a","Prabu Dharmaputra","pilihan_b","Prabu Puntadewa Agung","pilihan_c","Prabu Bharata","pilihan_d","Prabu Kalimataya","jawaban_benar","D","penjelasan","Ia bergelar Prabu Kalimataya (atau Prabu Dharmaputra/Yudistira di Hastina)."],q,p),A.W(["level",5,"kategori","Filosofi & Nilai Moral","pertanyaan",'Lakon "Pandawa Seda" menceritakan akhir kisah Pandawa yang...',"pilihan_a","Bertapa di Indraprastha","pilihan_b","Pindah ke Dwarawati","pilihan_c","Mendaki Gunung Himalaya menuju surga","pilihan_d","Mengasingkan diri","jawaban_benar","C","penjelasan","Pandawa menyerahkan takhta lalu mendaki Himalaya hingga satu per satu wafat."],q,p),A.W(["level",5,"kategori","Filosofi & Nilai Moral","pertanyaan","Secara utuh, Bharatayuda mengajarkan bahwa...","pilihan_a","Perang menyelesaikan masalah","pilihan_b","Yang kuat selalu menang","pilihan_c","Keadilan datang sendiri","pilihan_d","Kemenangan sejati dibayar mahal dan perang selalu membawa kehancuran","jawaban_benar","D","penjelasan","Pandawa menang namun kehilangan seluruh putra dan kerabat mereka."],q,p),A.W(["level",5,"kategori","Filosofi & Nilai Moral","pertanyaan","Pengorbanan Gatotkaca mengajarkan...","pilihan_a","Pengorbanan jiwa demi melindungi orang yang dicintai adalah kemuliaan ksatria","pilihan_b","Kepatuhan mutlak","pilihan_c","Kesaktian itu percuma","pilihan_d","Tragedi kematian","jawaban_benar","A","penjelasan","Gatotkaca mengorbankan dirinya agar Arjuna selamat dari panah Kunta milik Karna."],q,p),A.W(["level",5,"kategori","Filosofi & Nilai Moral","pertanyaan","Siapa yang mewarisi takhta Hastinapura dari Yudistira?","pilihan_a","Abimanyu","pilihan_b","Parikesit (cucu Arjuna)","pilihan_c","Janamejaya","pilihan_d","Gatotkaca","jawaban_benar","B","penjelasan","Parikesit, cucu Arjuna dari Abimanyu, adalah satu-satunya pewaris Dinasti Kuru yang tersisa."],q,p)]
