B.Tx=new A.b5(B.cA,["WAYANG KULIT PURWA","Wayang kulit adalah jenis wayang paling terkenal di Indonesia yang terbuat dari kulit sapi atau kerbau. Dimainkan dengan teknik bayangan (menggunakan kelir dan blencong), mengangkat kisah epik Mahabharata dan Ramayana.","KULIT (LEATHER)","assets/images/ui/jenis_wayang/wayang_kulit.webp"],t.l)
B.TC=new A.b5(B.cA,["WAYANG GOLEK","Boneka kayu tiga dimensi yang populer di tanah Sunda (Jawa Barat). Dipertontonkan tanpa layar bayangan, menggunakan bahasa Sunda, dan sering menyisipkan kisah bernuansa jenaka (Cepot) maupun epik lokal.","KAYU (WOODEN)","assets/images/ui/jenis_wayang/wayang_golek.webp"],t.l)
B.Tz=new A.b5(B.cA,["WAYANG ORANG (WONG)","Seni pertunjukan di mana tokoh wayang diperankan langsung oleh manusia dengan kostum, tata rias, dan tarian. Menggabungkan seni drama, tari, dan iringan gamelan khas keraton Jawa.","MANUSIA (HUMAN)","assets/images/ui/jenis_wayang/wayang_orang.webp"],t.l)
B.Ty=new A.b5(B.cA,["WAYANG BEBER","Salah satu bentuk wayang tertua di Indonesia. Ceritanya dilukis pada gulungan kain atau kertas (dibeber/dibentangkan). Dalang menceritakan kisah sambil menunjuk gambar pada gulungan tersebut.","GULUNGAN (SCROLL)","assets/images/ui/jenis_wayang/wayang_beber.webp"],t.l)
B.Tv=new A.b5(B.cA,["WAYANG KLITIK (KRUCIL)",'Wayang pipih yang terbuat dari kayu jati. Berbeda dengan wayang golek yang 3D, wayang klitik berbentuk 2D. Dinamakan klitik karena suara kayu yang berbenturan saat wayang digerakkan berbunyi "klitik-klitik".',"KAYU PIPIH (FLAT WOOD)","assets/images/ui/jenis_wayang/wayang_klitik.webp"],t.l)
B.Tt=new A.b5(B.cA,["WAYANG GEDOG","Mirip dengan wayang kulit purwa, namun khusus mengangkat cerita-cerita Panji (kisah romansa Raden Panji Asmarabangun dan Dewi Sekartaji) dari zaman Kerajaan Kediri dan Jenggala.","CERITA PANJI","assets/images/ui/jenis_wayang/wayang_gedog.webp"],t.l)
B.TA=new A.b5(B.cA,["WAYANG SULUH","Wayang modern yang muncul pada masa perjuangan kemendeerkaan Indonesia. Digunakan sebagai alat penerangan (penyuluhan) dan propaganda. Tokoh-tokohnya digambarkan seperti manusia modern.","PENYULUHAN (MODERN)","assets/images/ui/jenis_wayang/wayang_suluh.webp"],t.l)
B.TB=new A.b5(B.cA,["WAYANG WAHYU","Wayang kulit yang diciptakan untuk menyebarkan ajaran agama Katolik. Kisah yang diangkat diambil dari Alkitab, diciptakan oleh Bruder Timotheus L. Wignyosubroto pada tahun 1960-an.","KULIT (ALKITAB)","assets/images/ui/jenis_wayang/wayang_wahyu.webp"],t.l)
B.Tw=new A.b5(B.cA,["WAYANG POTEHI","Wayang boneka kain hasil asimilasi budaya Tionghoa dan Indonesia. Dimainkan dengan memasukkan tangan dalang ke dalam kantong boneka, biasanya membawakan kisah klasik Tiongkok kuno.","BONEKA KAIN (CLOTH)","assets/images/ui/jenis_wayang/wayang_potehi.webp"],t.l)
B.Tu=new A.b5(B.cA,["WAYANG SASAK","Wayang kulit khas dari Pulau Lombok, Nusa Tenggara Barat. Banyak dipengaruhi oleh penyebaran agama Islam, menceritakan kisah-kisah Serat Menak dengan tokoh utama Amir Hamzah.","KULIT (LOMBOK)","assets/images/ui/jenis_wayang/wayang_sasak.webp"],t.l)
